#!/usr/bin/env python3
"""
Generate Chain-of-Thought (CoT) instruction-completion pairs from real passed WordPress code.
Reads 40 diverse functions from data/phase1_extraction/output/passed/ (10+ repos) and
produces cot_real_code.json with step-by-step reasoning for each function.
"""

import json
import os
from pathlib import Path

PROJECT_ROOT = Path(__file__).resolve().parent.parent
BASE = str(PROJECT_ROOT / "data" / "phase1_extraction" / "output" / "passed")

TARGET_REPOS = [
    "advanced-custom-fields.json",
    "woocommerce-payments.json",
    "wordpress-seo.json",
    "google-site-kit.json",
    "amp-wp.json",
    "cmb2.json",
    "wp-super-cache.json",
    "wordpress-develop.json",
    "contact-form-7.json",
    "query-monitor.json",
    "woocommerce-gateway-stripe.json",
    "wordpress-importer.json",
    "edit-author-slug.json",
    "performance-lab.json",
    "varnish-http-purge.json",
]

SELECTED_INDICES = [3,4,10,11,15,16,17,19,20,23,24,25,26,27,28,29,30,32,33,38,39,40,42,45,46,47,49,50,52,53,55,57,60,61,63,64,65,68,70,71]


def load_selected():
    all_complex = []
    for fname in TARGET_REPOS:
        with open(f"{BASE}/{fname}") as f:
            data = json.load(f)
        complex_fns = [
            fn for fn in data
            if fn.get("line_count", 0) > 20
            and (fn.get("sql_patterns") or fn.get("hooks_used") or len(fn.get("training_tags", [])) > 2)
        ]
        complex_fns.sort(key=lambda x: x.get("line_count", 0), reverse=True)
        all_complex.extend(complex_fns[:5])
    return [all_complex[i] for i in SELECTED_INDICES]


