def determine_complexity(fn):
    lines = fn.get("line_count", 0)
    has_sql = bool(fn.get("sql_patterns"))
    tags_count = len(fn.get("training_tags", []))
    if lines > 100 or has_sql or tags_count > 8:
        return "complex"
    elif lines > 40 or tags_count > 4:
        return "medium"
    return "simple"


def build_entry(fn, cot):
    complexity = cot.get("complexity") or determine_complexity(fn)
    tags = fn.get("training_tags") or cot.get("training_tags", [])
    return {
        "task_type": "wp_gen",
        "instruction": cot["instruction"],
        "response": fn["body"],
        "cot_reasoning": cot["cot_reasoning"],
        "source_repo": fn["source_repo"],
        "source_file": fn.get("source_file", ""),
        "function_name": fn["function_name"],
        "training_tags": tags,
        "complexity": complexity,
        "line_count": fn.get("line_count", 0),
    }


def main():
    selected = load_selected()
    assert len(selected) == len(COT_DATA), (
        f"Mismatch: {len(selected)} functions vs {len(COT_DATA)} CoT entries"
    )

    output = []
    for fn, cot in zip(selected, COT_DATA):
        output.append(build_entry(fn, cot))

    out_dir = PROJECT_ROOT / "data" / "phase3_cot" / "output"
    out_dir.mkdir(parents=True, exist_ok=True)
    out_path = str(out_dir / "cot_real_code.json")
    with open(out_path, "w") as f:
        json.dump(output, f, indent=2, ensure_ascii=False)

    print(f"Written {len(output)} CoT entries to {out_path}")

    from collections import Counter
    complexities = Counter(e["complexity"] for e in output)
    repos = Counter(e["source_repo"] for e in output)
    total_lines = sum(e["line_count"] for e in output)

    print(f"\nComplexity breakdown: {dict(complexities)}")
    print(f"\nRepo coverage ({len(repos)} repos):")
    for repo, count in sorted(repos.items()):
        print(f"  {repo}: {count}")
    print(f"\nTotal lines of real code covered: {total_lines}")


if __name__ == "__main__":
    main()
